import React, { useMemo, useState } from "react";

/*
  SystemsOverview.jsx
  - Single-file React component to be rendered INSIDE AdminLayout
  - Tailwind CSS utility classes used for styling
  - Dummy JSON data included below (replace with ML verdict API response in production)

  Notes / Integration points (placeholders):
  - Backend will provide an ML verdict API that returns objects with the following shape:
      {
        id,                // unique system id
        owner,             // owner / department
        healthScore,       // 0-100 numeric (ML-decided health)
        status,            // "healthy" | "warning" | "critical"  (derived from healthScore)
        primaryRootCause,  // "Hardware" | "Software" | "Security"
        confidence,        // 0-100 numeric (ML confidence)
        lastSeen           // ISO timestamp string
      }

  - Filters -> Backend query params: when filtering server-side, send { status, primaryRootCause }
  - Details button -> Navigate to System Detail page (routing to be integrated by host app)
  - Assign button -> Opens technician assignment workflow / modal (to be implemented)

  UI / UX rules implemented:
  - No raw metrics, no charts (only ML-final verdicts)
  - Sticky table header, hover effects, accessible contrast
  - Responsive table with overflow handling
  - Empty state UI when no systems match filters
  - Loading placeholder is shown below as a commented section (replace with actual loader as needed)
*/

// -----------------------------
// Dummy data (for development / demo only)
// Backend will provide this from the ML verdict API
// -----------------------------
const DUMMY_SYSTEMS = [
  {
    id: "sys-1001",
    owner: "Manufacturing / Line A",
    healthScore: 92,
    status: "healthy",
    primaryRootCause: "Hardware",
    confidence: 96,
    lastSeen: new Date(Date.now() - 3 * 60 * 1000).toISOString(), // 3 min ago
  },
  {
    id: "sys-1002",
